query zoekConflicten {
    conflicten(
        first: 10
        agentschappen: ["WVG_VAPH"],
        zorgvoorzieningstypes: ["e13da695-58cf-4108-88fb-7e796876cef0"]
    ) {
        nodes {
            id
            type
            zorgvoorziening {
                id
                naam
                zorgvoorzieningstype {
                    id
                    naam
                }
            }
            gerelateerdeEntiteiten {
                type
                id
            }
        }

    }
}

