query zoekZorgvoorzieningen {
   zorgvoorzieningen(
     first: 10
     orderBy: NAAM_ASC
     naamOfHcoZoekterm: "200526"
     naam: "'t Gastenhuys"
     hcoNummer: "200526"
     agentschappen: ["WVG_VAPH"],
     zorgvoorzieningstypes: ["e13da695-58cf-4108-88fb-7e796876cef0"],
     zorgvoorzieningstypeCode: "034",
     skipIds: ["00000000-0000-0000-0000-000000000000"]
   ) {
     nodes {
       id
       naam
       hcoNummer
       zorgvoorzieningstype {
         naam
         agentschap {
           id
           afkorting
         }
       }
       inrichtendeMacht {
        naam
       }
     }
   }
 }

